{
  "version": "arkpilot-a2ui/v2",
  "kind": "semantic-ui-protocol",
  "appName": "今天吃什么",
  "targetDevice": {
    "widthVp": 1272,
    "heightVp": 2756,
    "contentMaxWidthVp": 420
  },
  "surfaces": [
    {
      "id": "home-page",
      "surfaceId": "home",
      "pageId": "home-page",
      "name": "首页",
      "route": "pages/Home",
      "tabId": "tab-home",
      "semanticTargets": [
        {
          "id": "home-spin-button",
          "role": "action",
          "event": "spin-wheel"
        },
        {
          "id": "home-wheel-result",
          "role": "assertion",
          "binding": "/wheel/selectedDish"
        },
        {
          "id": "home-recommend-button",
          "role": "action",
          "event": "open-ingredients-recommendations"
        },
        {
          "id": "home-history-snapshot",
          "role": "assertion",
          "binding": "/history/latestEntry"
        },
        {
          "id": "home-empty-history",
          "role": "assertion",
          "binding": "/history/isEmpty"
        }
      ]
    },
    {
      "id": "ingredients-page",
      "surfaceId": "ingredients",
      "pageId": "ingredients-page",
      "name": "冰箱食材",
      "route": "pages/Ingredients",
      "tabId": "tab-ingredients",
      "semanticTargets": [
        {
          "id": "ingredient-input",
          "role": "input",
          "event": "add-ingredient"
        },
        {
          "id": "ingredient-add-button",
          "role": "action",
          "event": "add-ingredient"
        },
        {
          "id": "ingredient-list",
          "role": "list",
          "binding": "/ingredients",
          "itemIdPattern": "ingredient-item-{id}",
          "emptyStateId": "ingredient-empty-state"
        },
        {
          "id": "ingredient-delete-{id}",
          "role": "action",
          "event": "delete-ingredient"
        },
        {
          "id": "ingredient-recommend-list",
          "role": "list",
          "binding": "/ingredients/recommendations",
          "itemIdPattern": "ingredient-dish-{id}",
          "emptyStateId": "ingredient-recommend-empty-state"
        },
        {
          "id": "ingredient-dish-{id}",
          "role": "action",
          "event": "select-dish"
        }
      ]
    },
    {
      "id": "filter-page",
      "surfaceId": "filter",
      "pageId": "filter-page",
      "name": "筛选推荐",
      "route": "pages/Filter",
      "tabId": "tab-filter",
      "semanticTargets": [
        {
          "id": "filter-mood-group",
          "role": "input",
          "binding": "/filter/selectedMoods"
        },
        {
          "id": "filter-time-group",
          "role": "input",
          "binding": "/filter/selectedTime"
        },
        {
          "id": "filter-apply-button",
          "role": "action",
          "event": "apply-filter"
        },
        {
          "id": "filter-reset-button",
          "role": "action",
          "event": "reset-filter"
        },
        {
          "id": "filter-result-list",
          "role": "list",
          "binding": "/filter/results",
          "itemIdPattern": "filter-dish-{id}",
          "emptyStateId": "filter-empty-state"
        },
        {
          "id": "filter-dish-{id}",
          "role": "action",
          "event": "select-dish"
        }
      ]
    },
    {
      "id": "history-page",
      "surfaceId": "history",
      "pageId": "history-page",
      "name": "饮食打卡",
      "route": "pages/History",
      "tabId": "tab-history",
      "semanticTargets": [
        {
          "id": "history-add-button",
          "role": "action",
          "event": "open-add-record-sheet"
        },
        {
          "id": "history-record-sheet",
          "role": "assertion",
          "binding": "/history/sheetVisible"
        },
        {
          "id": "history-record-input",
          "role": "input",
          "binding": "/history/newRecordText"
        },
        {
          "id": "history-record-save-button",
          "role": "action",
          "event": "save-record"
        },
        {
          "id": "history-list",
          "role": "list",
          "binding": "/history/records",
          "itemIdPattern": "history-record-{id}",
          "emptyStateId": "history-empty-state"
        },
        {
          "id": "history-record-{id}",
          "role": "assertion",
          "binding": "/history/records/{id}"
        },
        {
          "id": "history-share-button",
          "role": "action",
          "event": "share-record"
        },
        {
          "id": "history-share-sheet",
          "role": "assertion",
          "binding": "/history/shareSheetVisible"
        },
        {
          "id": "history-share-save-button",
          "role": "action",
          "event": "save-share-card"
        }
      ]
    }
  ],
  "events": [
    {
      "name": "spin-wheel",
      "description": "首页转盘开始旋转并随机选出菜品",
      "context": ["selectedDish"]
    },
    {
      "name": "open-ingredients-recommendations",
      "description": "从首页进入食材推荐",
      "context": []
    },
    {
      "name": "add-ingredient",
      "description": "添加冰箱食材",
      "context": ["name"]
    },
    {
      "name": "delete-ingredient",
      "description": "删除冰箱食材",
      "context": ["id"]
    },
    {
      "name": "select-dish",
      "description": "选择一道推荐菜",
      "context": ["dishId"]
    },
    {
      "name": "apply-filter",
      "description": "应用心情/时间筛选",
      "context": ["moods", "time"]
    },
    {
      "name": "reset-filter",
      "description": "重置筛选条件",
      "context": []
    },
    {
      "name": "open-add-record-sheet",
      "description": "打开添加打卡弹层",
      "context": []
    },
    {
      "name": "save-record",
      "description": "保存一条饮食打卡记录",
      "context": ["text", "timestamp"]
    },
    {
      "name": "share-record",
      "description": "为指定记录生成分享卡片",
      "context": ["recordId"]
    },
    {
      "name": "save-share-card",
      "description": "保存分享卡片图片",
      "context": ["recordId"]
    },
    {
      "name": "switch-tab",
      "description": "切换底部 Tab",
      "context": ["tabId"]
    }
  ],
  "bindings": {
    "/wheel/selectedDish": {
      "type": "object",
      "fields": ["id", "name", "tags", "timeSlots"]
    },
    "/ingredients": {
      "type": "array",
      "itemFields": ["id", "name"]
    },
    "/ingredients/recommendations": {
      "type": "array",
      "itemFields": ["id", "name", "tags", "matchedIngredients", "missingIngredients"]
    },
    "/filter/selectedMoods": {
      "type": "array",
      "itemType": "string"
    },
    "/filter/selectedTime": {
      "type": "string"
    },
    "/filter/results": {
      "type": "array",
      "itemFields": ["id", "name", "tags", "timeSlots"]
    },
    "/history/records": {
      "type": "array",
      "itemFields": ["id", "text", "timestamp"]
    },
    "/history/latestEntry": {
      "type": "object",
      "fields": ["id", "text", "timestamp"]
    },
    "/history/sheetVisible": {
      "type": "boolean"
    },
    "/history/shareSheetVisible": {
      "type": "boolean"
    }
  },
  "testTargets": [
    {
      "id": "home-spin-button",
      "action": "click",
      "assertAfter": "home-wheel-result should display non-empty dish name"
    },
    {
      "id": "ingredient-input",
      "action": "type",
      "value": "鸡蛋",
      "thenClick": "ingredient-add-button",
      "assertAfter": "ingredient-list contains ingredient-item-{id} with text 鸡蛋"
    },
    {
      "id": "filter-apply-button",
      "action": "click",
      "assertAfter": "filter-result-list shows dishes or filter-empty-state"
    },
    {
      "id": "history-add-button",
      "action": "click",
      "assertAfter": "history-record-sheet is visible"
    }
  ]
}

