{
  "uiTreePath": ".arkpilot/designs/ui-tree.json",
  "dataModel": {
    "entities": {
      "Dish": {
        "fields": ["id", "name", "tags", "moods", "timeSlots", "ingredients", "minutes"],
        "notes": "Built-in catalog entry. Not user data; loaded from DishLibrary. tags=display labels, moods=mood keys, timeSlots=time keys."
      },
      "Ingredient": {
        "fields": ["id", "name"],
        "persistence": "PersistentStorage key 'ingredients'",
        "seed": "empty"
      },
      "DishRecord": {
        "fields": ["id", "text", "timestamp"],
        "persistence": "PersistentStorage key 'records'",
        "seed": "empty"
      }
    },
    "settingsFormState": {
      "filter": {
        "selectedMoods": "string[] (subset of mood keys; persisted in-memory only)",
        "selectedTime": "string (one time key or empty)",
        "appliedResults": "Dish[] computed on apply-filter"
      },
      "wheel": {
        "selectedDish": "Dish | null (in-memory only)"
      },
      "history": {
        "sheetVisible": "boolean (add-record sheet)",
        "shareSheetVisible": "boolean (share-card sheet)",
        "newRecordText": "string",
        "activeShareRecord": "DishRecord | null"
      }
    },
    "computedState": {
      "ingredientsRecommendations": "Dish[] sorted by ingredient match% desc, only matched>=1",
      "historyLatestEntry": "DishRecord | null (first of records, newest first)",
      "historyStats": "{weekCount, streakDays, shareCount}"
    }
  },
  "services": {
    "DishLibrary": "Static built-in catalog of dishes (no network). Source of wheel picks, filter results, ingredient recommendations.",
    "RecommendService": "Pure function: recommend(ingredients) -> Dish[] with match% via intersection of dish.ingredients and user ingredient names.",
    "FilterService": "Pure function: filter(moods, time) -> Dish[] intersecting mood and time, all-pass when selection empty.",
    "Persistence": "PersistentStorage on keys 'ingredients' and 'records'. No explicit flush needed; app data only."
  },
  "stateMachine": {
    "wheel": {
      "states": ["idle", "spinning", "settled"],
      "transitions": [
        { "from": "idle|settled", "event": "spin-wheel", "to": "spinning", "sideEffect": "animate rotation, then pick random Dish -> settled, set /wheel/selectedDish" }
      ]
    },
    "historySheet": {
      "states": ["closed", "open"],
      "transitions": [
        { "from": "closed", "event": "open-add-record-sheet", "to": "open" },
        { "from": "open", "event": "save-record", "to": "closed", "sideEffect": "prepend new DishRecord, clear newRecordText" },
        { "from": "open", "event": "close-sheet", "to": "closed" }
      ]
    },
    "shareSheet": {
      "states": ["closed", "open"],
      "transitions": [
        { "from": "closed", "event": "share-record", "to": "open", "sideEffect": "set activeShareRecord" },
        { "from": "open", "event": "save-share-card", "to": "open", "sideEffect": "persist/confirm save (toast)" },
        { "from": "open", "event": "close-sheet", "to": "closed" }
      ]
    }
  },
  "interactionFlows": [
    {
      "id": "home-spin",
      "trigger": "click home-spin-button",
      "steps": ["disable button", "animate wheel rotation", "pick random dish from DishLibrary", "render in home-wheel-result"],
      "expectedState": "/wheel/selectedDish non-empty",
      "error": "no dishes available -> show result placeholder"
    },
    {
      "id": "home-to-ingredients",
      "trigger": "click home-recommend-button",
      "steps": ["switch-tab to tab-ingredients"],
      "expectedState": "ingredients surface active"
    },
    {
      "id": "add-ingredient",
      "trigger": "type ingredient-input then click ingredient-add-button (or enter)",
      "steps": ["trim text", "reject empty/duplicate (case-insensitive)", "append Ingredient", "persist", "recompute recommendations", "clear input"],
      "expectedState": "/ingredients contains ingredient-item-{id}; ingredient-list visible or ingredient-empty-state when empty"
    },
    {
      "id": "delete-ingredient",
      "trigger": "click ingredient-delete-{id}",
      "steps": ["remove Ingredient by id", "persist", "recompute recommendations"],
      "expectedState": "item removed"
    },
    {
      "id": "ingredients-recommend",
      "trigger": "/ingredients change",
      "steps": ["RecommendService.recommend(ingredients)", "sort by match% desc"],
      "expectedState": "ingredient-recommend-list populated or ingredient-recommend-empty-state"
    },
    {
      "id": "apply-filter",
      "trigger": "click filter-apply-button",
      "steps": ["FilterService.filter(selectedMoods, selectedTime)", "set /filter/results"],
      "expectedState": "filter-result-list populated or filter-empty-state"
    },
    {
      "id": "reset-filter",
      "trigger": "click filter-reset-button",
      "steps": ["clear selectedMoods and selectedTime", "recompute results (all dishes)"],
      "expectedState": "all dishes shown"
    },
    {
      "id": "toggle-mood",
      "trigger": "click mood chip in filter-mood-group",
      "steps": ["toggle mood in selectedMoods"]
    },
    {
      "id": "toggle-time",
      "trigger": "click time chip in filter-time-group",
      "steps": ["set selectedTime (single-select)"]
    },
    {
      "id": "open-add-record",
      "trigger": "click history-add-button",
      "steps": ["show history-record-sheet"],
      "expectedState": "/history/sheetVisible true"
    },
    {
      "id": "save-record",
      "trigger": "type history-record-input then click history-record-save-button",
      "steps": ["trim", "reject empty", "prepend DishRecord {id, text, timestamp=now}", "persist", "close sheet", "clear newRecordText"],
      "expectedState": "/history/records contains history-record-{id}; newest first; history-empty-state when empty"
    },
    {
      "id": "share-record",
      "trigger": "click history-share-button",
      "steps": ["set activeShareRecord", "show history-share-sheet"],
      "expectedState": "/history/shareSheetVisible true"
    },
    {
      "id": "save-share-card",
      "trigger": "click history-share-save-button",
      "steps": ["confirm save (toast)"],
      "expectedState": "sheet stays open; feedback shown"
    },
    {
      "id": "switch-tab",
      "trigger": "tap BottomTabBar item",
      "steps": ["set activeTab + surface"]
    }
  ],
  "testTargets": [
    { "id": "home-spin-button", "action": "click", "assertAfter": "home-wheel-result shows a dish name" },
    { "id": "ingredient-input", "action": "type 鸡蛋", "thenClick": "ingredient-add-button", "assertAfter": "ingredient-list has item 鸡蛋" },
    { "id": "filter-apply-button", "action": "click", "assertAfter": "filter-result-list shows dishes or filter-empty-state" },
    { "id": "history-add-button", "action": "click", "assertAfter": "history-record-sheet visible" },
    { "id": "history-record-save-button", "action": "click (after typing)", "assertAfter": "new record in history-list" }
  ],
  "moodKeys": ["crave", "light", "diet", "treat"],
  "moodLabels": { "crave": "想吃爽", "light": "清淡点", "diet": "减脂中", "treat": "想犒劳" },
  "moodColors": { "crave": "#D94E41", "light": "#4A8B5D", "diet": "#E8A63C", "treat": "#A88FB8" },
  "timeKeys": ["breakfast", "lunch", "dinner", "lateNight"],
  "timeLabels": { "breakfast": "早餐", "lunch": "午餐", "dinner": "晚餐", "lateNight": "夜宵" },
  "notes": "All semantic IDs from ui-tree.json preserved kebab-case. Tabs: tab-home/tab-ingredients/tab-filter/tab-history. No backend; fully offline. Built-in DishLibrary is a catalog (allowed by spec) not seeded user data."
}

