// Theme.ets
//
// Semantic theme tokens for 今天吃什么.
// Warm food palette per .arkpilot/plans/design-alignment.md.
// Keep the exported class names as Theme and BrandGradient; keep layout
// contract tokens (pageHorizontalPadding, bottomTabHeight, contentMaxWidth)
// stable for the fixed bottom-tab shell.

export class Theme {
  // Backgrounds & surfaces
  static readonly pageBg: string = '#FFF9ED';
  static readonly cardBg: string = '#FFFFFF';
  static readonly surfaceSecondary: string = '#F5EBD9';
  static readonly heroGlowStart: string = 'rgba(232,166,60,0.24)';

  // Brand / food accents
  static readonly mustard: string = '#E8A63C';      // primary accent (selected tab, primary)
  static readonly caramel: string = '#D97C4B';      // gradient end / dish icon
  static readonly tomato: string = '#D94E41';       // pointer / crave
  static readonly basil: string = '#4A8B5D';        // light mood
  static readonly lavender: string = '#A88FB8';     // treat mood

  // Text
  static readonly textPrimary: string = '#3B322A';
  static readonly textSecondary: string = '#9A8E7F';
  static readonly textOnPrimary: string = '#FFFFFF';
  static readonly textPlaceholder: string = '#9A8E7F';

  // Lines / borders
  static readonly borderSoft: string = 'rgba(59,50,42,0.06)';
  static readonly borderDashed: string = 'rgba(59,50,42,0.12)';
  static readonly timelineTrack: string = '#F5EBD9';

  // Backdrop
  static readonly backdrop: string = 'rgba(59,50,42,0.50)';

  // Radii
  static readonly radiusChip: number = 18;
  static readonly radiusTag: number = 14;
  static readonly radiusCard: number = 22;
  static readonly radiusHero: number = 24;
  static readonly radiusButton: number = 28;
  static readonly radiusSecondaryButton: number = 24;
  static readonly radiusInput: number = 18;
  static readonly radiusSheetTop: number = 28;
  static readonly radiusSmall: number = 16;
  static readonly radiusIconTile: number = 16;

  // Layout contract (do not change shell assumptions)
  static readonly pageHorizontalPadding: number = 22;
  static readonly headerTopPadding: number = 56;
  static readonly bottomTabHeight: number = 64;
  static readonly contentMaxWidth: number = 390;
  static readonly touchTarget: number = 44;
}

export class BrandGradient {
  // Primary button / selected chip / add buttons
  static readonly primary: LinearGradient = {
    angle: 135,
    direction: GradientDirection.RightTop,
    colors: [[Theme.mustard, 0.0], [Theme.caramel, 1.0]],
  } as LinearGradient;

  // Share card warm wash
  static readonly shareWash: LinearGradient = {
    angle: 135,
    direction: GradientDirection.RightTop,
    colors: [[Theme.pageBg, 0.0], [Theme.surfaceSecondary, 1.0]],
  } as LinearGradient;
}

