// BottomTabBar.ets
//
// Fixed bottom-tab shell component for 今天吃什么.
// Public API (stable): activeTab and onTap. Icon variants switch between
// prepared active/inactive rawfile SVGs (no tinting of stroke-mode icons).
import { SvgIcon } from '../common/SvgIcon';
import { TabId } from '../common/TabTypes';
import { Theme } from '../common/Theme';

interface TabDescriptor {
  id: TabId;
  label: string;
  icon: string;
  iconActive: string;
}

const TABS: TabDescriptor[] = [
  { id: 'tab-home', label: '首页', icon: 'home', iconActive: 'home-active' },
  { id: 'tab-ingredients', label: '食材', icon: 'ingredients', iconActive: 'ingredients-active' },
  { id: 'tab-filter', label: '筛选', icon: 'filter', iconActive: 'filter-active' },
  { id: 'tab-history', label: '记录', icon: 'history', iconActive: 'history-active' },
];

@Component
export struct BottomTabBar {
  @Prop activeTab: TabId;
  onTap: (tab: TabId) => void = () => {};

  build() {
    Row() {
      ForEach(TABS, (tab: TabDescriptor) => {
        Column() {
          SvgIcon({
            variant: this.activeTab === tab.id ? tab.iconActive : tab.icon,
            iconSize: 24,
            color: this.activeTab === tab.id ? Theme.mustard : Theme.textSecondary,
            strokeWidth: 2
          })
          Text(tab.label)
            .fontSize(11)
            .fontWeight(FontWeight.Medium)
            .fontColor(this.activeTab === tab.id ? Theme.mustard : Theme.textSecondary)
            .margin({ top: 4 })
        }
        .id(tab.id)
        .padding({ left: 16, right: 16, top: 8, bottom: 8 })
        .onClick(() => this.onTap(tab.id))
        .layoutWeight(1)
        .alignItems(HorizontalAlign.Center)
        .justifyContent(FlexAlign.Center)
      }, (tab: TabDescriptor) => tab.id)
    }
    .width('100%')
    .height(Theme.bottomTabHeight)
    .backgroundColor(Theme.cardBg)
    .border({ width: { top: 1 }, color: { top: Theme.borderSoft } })
    .shadow({ radius: 20, color: 'rgba(59,50,42,0.06)', offsetY: -4 })
    .justifyContent(FlexAlign.SpaceAround)
    .alignItems(VerticalAlign.Center)
  }
}

