// RecommendService.ets
//
// Pure recommendation logic: score the dish catalog against the user's fridge
// ingredients and return dishes with at least one matched ingredient, sorted by
// match percentage descending.
import { Dish, DishRecommendation, Ingredient } from '../models/Models';
import { DishLibrary } from '../data/DishLibrary';

export class RecommendService {
  static recommend(ingredients: Ingredient[]): DishRecommendation[] {
    const owned = new Set<string>();
    ingredients.forEach((i) => owned.add(i.name.trim()));
    if (owned.size === 0) {
      return [];
    }
    const scored: DishRecommendation[] = [];
    DishLibrary.all().forEach((dish) => {
      const matched: string[] = [];
      const missing: string[] = [];
      dish.ingredients.forEach((ing) => {
        if (owned.has(ing)) {
          matched.push(ing);
        } else {
          missing.push(ing);
        }
      });
      if (matched.length === 0) {
        return;
      }
      const matchPercent = Math.round((matched.length / dish.ingredients.length) * 100);
      scored.push({ dish, matched, missing, matchPercent });
    });
    scored.sort((a, b) => b.matchPercent - a.matchPercent);
    return scored;
  }
}

