// FilterService.ets
//
// Pure filter logic: narrow the dish catalog by selected moods and meal time.
// When a selection is empty it passes all dishes for that dimension.
import { Dish, MoodKey, TimeKey } from '../models/Models';
import { DishLibrary } from '../data/DishLibrary';

export class FilterService {
  static filter(moods: MoodKey[], time: TimeKey | ''): Dish[] {
    return DishLibrary.all().filter((dish) => {
      const moodOk = moods.length === 0 || moods.some((m) => dish.moods.includes(m));
      const timeOk = time === '' || dish.timeSlots.includes(time);
      return moodOk && timeOk;
    });
  }
}

