// AppStore.ets
//
// Central reactive store over AppStorage. Ingredients and records are
// persisted via PersistentStorage (auto-flush to disk on change); the rest
// (wheel result, filter state, sheet visibility) is in-memory page state.
//
// Pages bind with @StorageLink('ingredients') / @StorageLink('records') and
// call the mutation helpers here. Each helper replaces the AppStorage value
// (whole-array reassignment) so every linked @StorageLink re-renders and the
// persisted copy stays in sync.
import { Ingredient, DishRecord } from '../models/Models';

export class AppStore {
  static readonly KEY_INGREDIENTS: string = 'ingredients';
  static readonly KEY_RECORDS: string = 'records';

  // Call once from EntryAbility.onCreate before the UI loads.
  static init(): void {
    PersistentStorage.persistProp(AppStore.KEY_INGREDIENTS, []);
    PersistentStorage.persistProp(AppStore.KEY_RECORDS, []);
  }

  // ---- Ingredients ----
  static getIngredients(): Ingredient[] {
    return AppStorage.get<Ingredient[]>(AppStore.KEY_INGREDIENTS) ?? [];
  }

  // Returns false if rejected (empty / duplicate).
  static addIngredient(rawName: string): boolean {
    const name = rawName.trim();
    if (name.length === 0) {
      return false;
    }
    const current = AppStore.getIngredients();
    const exists = current.some((i) => i.name === name);
    if (exists) {
      return false;
    }
    const next: Ingredient[] = [...current, { id: `ing_${Date.now()}`, name }];
    AppStorage.set<Ingredient[]>(AppStore.KEY_INGREDIENTS, next);
    return true;
  }

  static deleteIngredient(id: string): void {
    const next = AppStore.getIngredients().filter((i) => i.id !== id);
    AppStorage.set<Ingredient[]>(AppStore.KEY_INGREDIENTS, next);
  }

  // ---- Records ----
  static getRecords(): DishRecord[] {
    return AppStorage.get<DishRecord[]>(AppStore.KEY_RECORDS) ?? [];
  }

  // Returns false if rejected (empty).
  static addRecord(rawText: string): boolean {
    const text = rawText.trim();
    if (text.length === 0) {
      return false;
    }
    const current = AppStore.getRecords();
    const record: DishRecord = { id: `rec_${Date.now()}`, text, timestamp: Date.now() };
    // newest first
    const next: DishRecord[] = [record, ...current];
    AppStorage.set<DishRecord[]>(AppStore.KEY_RECORDS, next);
    return true;
  }

  static getLatestRecord(): DishRecord | null {
    const records = AppStore.getRecords();
    return records.length > 0 ? records[0] : null;
  }
}

