// Models.ets
//
// Domain models for 今天吃什么. Shared across services, store, and pages.

// Mood keys (match ui-behavior.json moodKeys)
export type MoodKey = 'crave' | 'light' | 'diet' | 'treat';
// Time keys (match ui-behavior.json timeKeys)
export type TimeKey = 'breakfast' | 'lunch' | 'dinner' | 'lateNight';

// Built-in catalog dish. This is a recipe catalog (allowed by spec), not
// seeded user data. Used by wheel, filter, and ingredient recommendations.
export interface Dish {
  id: string;
  name: string;
  tags: string[];        // display labels, e.g. 家常菜, 清淡, 快手
  moods: MoodKey[];      // mood contexts this dish fits
  timeSlots: TimeKey[];  // meal times this dish fits
  ingredients: string[]; // common ingredients (for ingredient matching)
  minutes: number;
}

// A user ingredient persisted in the fridge.
export interface Ingredient {
  id: string;
  name: string;
}

// A daily eating check-in record.
export interface DishRecord {
  id: string;
  text: string;
  timestamp: number; // epoch ms
}

// A dish scored against the user's current ingredients.
export interface DishRecommendation {
  dish: Dish;
  matched: string[];
  missing: string[];
  matchPercent: number;
}

export const MOOD_LABELS: Record<MoodKey, string> = {
  crave: '想吃爽',
  light: '清淡点',
  diet: '减脂中',
  treat: '想犒劳',
};

export const MOOD_COLORS: Record<MoodKey, string> = {
  crave: '#D94E41',
  light: '#4A8B5D',
  diet: '#E8A63C',
  treat: '#A88FB8',
};

export const TIME_LABELS: Record<TimeKey, string> = {
  breakfast: '早餐',
  lunch: '午餐',
  dinner: '晚餐',
  lateNight: '夜宵',
};

export const MOOD_ORDER: MoodKey[] = ['crave', 'light', 'diet', 'treat'];
export const TIME_ORDER: TimeKey[] = ['breakfast', 'lunch', 'dinner', 'lateNight'];

// RecommendService.ets
//
// Pure recommendation logic: score the dish catalog against the user's fridge
// ingredients and return dishes with at least one matched ingredient, sorted by
// match percentage descending.
import { Dish, DishRecommendation, Ingredient } from '../models/Models';
import { DishLibrary } from '../data/DishLibrary';

export class RecommendService {
  static recommend(ingredients: Ingredient[]): DishRecommendation[] {
    const owned = new Set<string>();
    ingredients.forEach((i) => owned.add(i.name.trim()));
    if (owned.size === 0) {
      return [];
    }
    const scored: DishRecommendation[] = [];
    DishLibrary.all().forEach((dish) => {
      const matched: string[] = [];
      const missing: string[] = [];
      dish.ingredients.forEach((ing) => {
        if (owned.has(ing)) {
          matched.push(ing);
        } else {
          missing.push(ing);
        }
      });
      if (matched.length === 0) {
        return;
      }
      const matchPercent = Math.round((matched.length / dish.ingredients.length) * 100);
      scored.push({ dish, matched, missing, matchPercent });
    });
    scored.sort((a, b) => b.matchPercent - a.matchPercent);
    return scored;
  }
}

