// Format.ets
//
// Small display helpers shared across pages.

export class Format {
  static greeting(): string {
    const h = new Date().getHours();
    if (h < 6) {
      return '夜深了，想吃点夜宵吗？';
    }
    if (h < 11) {
      return '早上好，今天想吃点什么？';
    }
    if (h < 14) {
      return '中午好，今天想吃点什么？';
    }
    if (h < 18) {
      return '下午好，有点馋了吗？';
    }
    return '晚上好，今天想吃点什么？';
  }

  // Today/yesterday-relative clock string, e.g. 今天 08:30 / 昨天 19:30 / 06/16 12:15
  static recordTime(ts: number): string {
    const d = new Date(ts);
    const now = new Date();
    const hm = `${Format.pad(d.getHours())}:${Format.pad(d.getMinutes())}`;
    const startOfToday = new Date(now.getFullYear(), now.getMonth(), now.getDate()).getTime();
    const dayMs = 24 * 60 * 60 * 1000;
    const dayDiff = Math.floor((startOfToday - new Date(d.getFullYear(), d.getMonth(), d.getDate()).getTime()) / dayMs);
    if (dayDiff <= 0) {
      return `今天 ${hm}`;
    }
    if (dayDiff === 1) {
      return `昨天 ${hm}`;
    }
    return `${Format.pad(d.getMonth() + 1)}/${Format.pad(d.getDate())} ${hm}`;
  }

  // Full date for the share card, e.g. 2026/06/18
  static shareDate(ts: number): string {
    const d = new Date(ts);
    return `${d.getFullYear()}/${Format.pad(d.getMonth() + 1)}/${Format.pad(d.getDate())}`;
  }

  private static pad(n: number): string {
    return n < 10 ? `0${n}` : `${n}`;
  }
}

