// Wheel.ets
//
// Home decision wheel. Renders 6 alternating sectors via Canvas plus a fixed
// tomato center disc and a fixed top pointer. The parent drives the rotation
// by animating the `angle` prop inside an animateTo block.
import { Theme } from '../common/Theme';
import { SvgIcon } from '../common/SvgIcon';

@Component
export struct Wheel {
  @Prop angle: number = 0;

  private settings: RenderingContextSettings = new RenderingContextSettings(true);
  private context: CanvasRenderingContext2D = new CanvasRenderingContext2D(this.settings);
  private readonly size: number = 280;
  private readonly center: number = 140;
  private readonly radius: number = 140;

  build() {
    Stack() {
      Canvas(this.context)
        .width(this.size)
        .height(this.size)
        .onReady(() => this.draw())
        .rotate({ angle: this.angle })

      // Fixed tomato center disc with the pointer glyph.
      Column() {
        SvgIcon({ variant: 'wheel-center', iconSize: 32, color: Theme.textOnPrimary })
      }
      .width(72)
      .height(72)
      .borderRadius(36)
      .backgroundColor(Theme.tomato)
      .shadow({ radius: 14, color: 'rgba(217,78,65,0.35)', offsetY: 4 })
      .justifyContent(FlexAlign.Center)
      .alignItems(HorizontalAlign.Center)

      // Fixed top pointer triangle.
      Column()
        .width(0)
        .height(0)
        .border({ width: { top: 16, left: 10, right: 10 }, color: { top: Theme.tomato, left: Color.Transparent, right: Color.Transparent } })
        .position({ x: '50%', y: 0 })
        .markAnchor({ x: '0%', y: 0 })
    }
    .width(this.size)
    .height(this.size)
    .alignContent(Alignment.Center)
  }

  private draw(): void {
    const ctx = this.context;
    ctx.clearRect(0, 0, this.size, this.size);
    // 6 sectors of 60deg, alternating cream/oat.
    for (let i = 0; i < 6; i++) {
      const startDeg = i * 60 - 90;
      const endDeg = (i + 1) * 60 - 90;
      ctx.beginPath();
      ctx.moveTo(this.center, this.center);
      ctx.arc(this.center, this.center, this.radius, startDeg * Math.PI / 180, endDeg * Math.PI / 180);
      ctx.closePath();
      ctx.fillStyle = i % 2 === 0 ? '#FFFFFF' : '#F5EBD9';
      ctx.fill();
    }
    // Dashed inner ring.
    ctx.beginPath();
    ctx.arc(this.center, this.center, this.radius - 14, 0, Math.PI * 2);
    ctx.strokeStyle = 'rgba(154,142,127,0.25)';
    ctx.lineWidth = 2;
    ctx.setLineDash([8, 8]);
    ctx.stroke();
    ctx.setLineDash([]);
  }
}

