// HomePage.ets
//
// 首页: decision wheel + today's recommendation + latest check-in snapshot.
import { Theme, BrandGradient } from '../common/Theme';
import { TabId } from '../common/TabTypes';
import { SvgIcon } from '../common/SvgIcon';
import { Wheel } from '../components/Wheel';
import { EmptyState } from '../components/EmptyState';
import { Dish, DishRecord, Ingredient, TIME_LABELS, TimeKey } from '../common/models/Models';
import { DishLibrary } from '../common/data/DishLibrary';
import { RecommendService } from '../common/services/RecommendService';
import { Format } from '../common/util/Format';
import { promptAction } from '@kit.ArkUI';

@Component
export struct HomePage {
  goToTab: (tab: TabId) => void = () => {};

  @State greeting: string = '今天想吃点什么？';
  @State wheelAngle: number = 0;
  @State spinning: boolean = false;
  @State selectedDish: Dish | null = null;
  @StorageLink('ingredients') ingredients: Ingredient[] = [];
  @StorageLink('records') records: DishRecord[] = [];

  aboutToAppear(): void {
    this.greeting = Format.greeting();
  }

  build() {
    Column() {
      Scroll() {
        Column() {
          this.Header()
          this.WheelSection()
          this.TodayRecommendSection()
          this.LatestCheckInSection()
        }
        .width('100%')
        .alignItems(HorizontalAlign.Start)
      }
      .layoutWeight(1)
      .scrollBar(BarState.Off)
      .align(Alignment.Start)
    }
    .width('100%')
    .height('100%')
    .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding })
  }

  @Builder
  Header(): void {
    Column() {
      Text(this.greeting)
        .fontSize(15)
        .fontColor(Theme.textSecondary)
        .margin({ bottom: 4 })
      Text('今天吃什么')
        .fontSize(32)
        .fontWeight(FontWeight.Bold)
        .fontColor(Theme.textPrimary)
    }
    .width('100%')
    .alignItems(HorizontalAlign.Start)
    .padding({ top: Theme.headerTopPadding, bottom: 24 })
  }

  @Builder
  WheelSection(): void {
    Column() {
      Wheel({ angle: this.wheelAngle })
        .margin({ bottom: 24 })

      // Result card bound to home-wheel-result.
      Column() {
        Text('为你选中')
          .fontSize(13)
          .fontColor(Theme.textSecondary)
          .margin({ bottom: 6 })
        Text(this.selectedDish === null ? '点击下方按钮，开始今天的决定' : this.selectedDish.name)
          .fontSize(this.selectedDish === null ? 16 : 24)
          .fontWeight(this.selectedDish === null ? FontWeight.Normal : FontWeight.Bold)
          .fontColor(this.selectedDish === null ? Theme.textSecondary : Theme.textPrimary)
          .margin({ bottom: this.selectedDish === null ? 0 : 12 })

        if (this.selectedDish !== null) {
          Flex({ wrap: FlexWrap.Wrap, justifyContent: FlexAlign.Center }) {
            ForEach(this.selectedDish.tags, (tag: string, idx: number) => {
              Text(tag)
                .fontSize(12)
                .fontWeight(FontWeight.Medium)
                .fontColor(idx === 0 ? Theme.textOnPrimary : Theme.textPrimary)
                .backgroundColor(idx === 0 ? Theme.mustard : Theme.surfaceSecondary)
                .borderRadius(Theme.radiusChip)
                .padding({ left: 12, right: 12, top: 6, bottom: 6 })
                .margin({ left: 4, right: 4 })
            }, (tag: string, idx: number) => `${idx}-${tag}`)
          }
        }
      }
      .id('home-wheel-result')
      .width('100%')
      .padding(20)
      .backgroundColor(Theme.cardBg)
      .border({ width: 1, color: Theme.borderSoft })
      .borderRadius(Theme.radiusCard)
      .shadow({ radius: 30, color: 'rgba(59,50,42,0.12)', offsetY: 10 })
      .alignItems(HorizontalAlign.Center)
      .margin({ bottom: 20 })

      Button() {
        Row() {
          SvgIcon({ variant: 'spin', iconSize: 20, color: Theme.textOnPrimary })
          Text(this.spinning ? '旋转中…' : '开始转盘')
            .fontSize(16)
            .fontWeight(FontWeight.Medium)
            .fontColor(Theme.textOnPrimary)
            .margin({ left: 8 })
        }
      }
      .id('home-spin-button')
      .type(ButtonType.Normal)
      .width('100%')
      .height(52)
      .borderRadius(Theme.radiusButton)
      .linearGradient(BrandGradient.primary)
      .shadow({ radius: 18, color: 'rgba(232,166,60,0.40)', offsetY: 6 })
      .enabled(!this.spinning)
      .onClick(() => this.spin())
    }
    .width('100%')
    .alignItems(HorizontalAlign.Center)
    .margin({ bottom: 28 })
  }

  @Builder
  TodayRecommendSection(): void {
    Column() {
      Row() {
        Text('今日推荐')
          .fontSize(20)
          .fontWeight(FontWeight.Medium)
          .fontColor(Theme.textPrimary)
        Blank()
        Row() {
          Text('按食材推荐')
            .fontSize(14)
            .fontColor(Theme.mustard)
            .fontWeight(FontWeight.Medium)
          SvgIcon({ variant: 'arrow-right', iconSize: 16, color: Theme.mustard })
        }
        .id('home-recommend-button')
        .onClick(() => this.goToTab('tab-ingredients'))
      }
      .width('100%')
      .alignItems(VerticalAlign.Center)
      .margin({ bottom: 14 })

      this.TodayRecommendCard()
    }
    .width('100%')
    .alignItems(HorizontalAlign.Start)
    .margin({ bottom: 20 })
  }

  @Builder
  TodayRecommendCard(): void {
    Row() {
      Column() {
        SvgIcon({ variant: 'recommend', iconSize: 24, color: Theme.caramel })
      }
      .width(48)
      .height(48)
      .borderRadius(24)
      .backgroundColor(Theme.surfaceSecondary)
      .justifyContent(FlexAlign.Center)
      .alignItems(HorizontalAlign.Center)

      Column() {
        Text(this.todayDishName())
          .fontSize(17)
          .fontWeight(FontWeight.Medium)
          .fontColor(Theme.textPrimary)
          .margin({ bottom: 2 })
        Text(this.todayDishMeta())
          .fontSize(13)
          .fontColor(Theme.textSecondary)
      }
      .layoutWeight(1)
      .alignItems(HorizontalAlign.Start)
      .margin({ left: 14 })
    }
    .width('100%')
    .padding({ left: 20, right: 20, top: 18, bottom: 18 })
    .backgroundColor(Theme.cardBg)
    .border({ width: 1, color: Theme.borderSoft })
    .borderRadius(Theme.radiusCard)
    .shadow({ radius: 30, color: 'rgba(59,50,42,0.12)', offsetY: 10 })
    .alignItems(VerticalAlign.Center)
    .onClick(() => this.goToTab('tab-ingredients'))
  }

  @Builder
  LatestCheckInSection(): void {
    Column() {
      Text('最近打卡')
        .fontSize(20)
        .fontWeight(FontWeight.Medium)
        .fontColor(Theme.textPrimary)
        .margin({ bottom: 14 })

      if (this.records.length === 0) {
        EmptyState({
          iconVariant: 'empty-home',
          title: '还没有打卡',
          subtitle: '记录第一餐，开启饮食手账',
          targetId: 'home-empty-history'
        })
      } else {
        Row() {
          Column() {
            SvgIcon({ variant: 'latest', iconSize: 24, color: Theme.caramel })
          }
          .width(48)
          .height(48)
          .borderRadius(24)
          .backgroundColor(Theme.surfaceSecondary)
          .justifyContent(FlexAlign.Center)
          .alignItems(HorizontalAlign.Center)

          Column() {
            Text(this.records[0].text)
              .fontSize(17)
              .fontWeight(FontWeight.Medium)
              .fontColor(Theme.textPrimary)
              .margin({ bottom: 2 })
            Text(Format.recordTime(this.records[0].timestamp))
              .fontSize(13)
              .fontColor(Theme.textSecondary)
          }
          .layoutWeight(1)
          .alignItems(HorizontalAlign.Start)
          .margin({ left: 14 })
        }
        .id('home-history-snapshot')
        .width('100%')
        .padding({ left: 20, right: 20, top: 18, bottom: 18 })
        .backgroundColor(Theme.cardBg)
        .border({ width: 1, color: Theme.borderSoft })
        .borderRadius(Theme.radiusCard)
        .shadow({ radius: 30, color: 'rgba(59,50,42,0.12)', offsetY: 10 })
        .alignItems(VerticalAlign.Center)
        .onClick(() => this.goToTab('tab-history'))
      }
    }
    .width('100%')
    .alignItems(HorizontalAlign.Start)
  }

  private spin(): void {
    if (this.spinning) {
      return;
    }
    this.spinning = true;
    const extra = 360 * 5 + Math.floor(Math.random() * 360);
    animateTo({
      duration: 2600,
      curve: Curve.EaseOut,
      onFinish: () => {
        this.selectedDish = DishLibrary.randomPick();
        this.spinning = false;
      }
    }, () => {
      this.wheelAngle += extra;
    });
  }

  // Picks a "today" recommendation: top ingredient match if the fridge has
  // ingredients, otherwise a time-of-day pick from the catalog.
  private todayDishName(): string {
    return this.todayDish().name;
  }

  private todayDishMeta(): string {
    const recs = RecommendService.recommend(this.ingredients);
    if (recs.length > 0) {
      const top = recs[0];
      const matchedText = top.matched.length > 0 ? `已匹配 ${top.matched.join('、')}` : '';
      const percent = `匹配度 ${top.matchPercent}%`;
      return matchedText.length > 0 ? `${matchedText} · ${percent}` : percent;
    }
    const dish = this.todayDish();
    const slotLabel = dish.timeSlots.length > 0 ? TIME_LABELS[dish.timeSlots[0]] : '';
    return `${slotLabel} · 推荐 · ${dish.minutes} 分钟`;
  }

  private todayDish(): Dish {
    const recs = RecommendService.recommend(this.ingredients);
    if (recs.length > 0) {
      return recs[0].dish;
    }
    const h = new Date().getHours();
    let slot: TimeKey = 'lunch';
    if (h < 10) {
      slot = 'breakfast';
    } else if (h < 14) {
      slot = 'lunch';
    } else if (h < 18) {
      slot = 'dinner';
    } else {
      slot = 'lateNight';
    }
    const bySlot = DishLibrary.all().filter((d) => d.timeSlots.includes(slot));
    return bySlot.length > 0 ? bySlot[0] : DishLibrary.all()[0];
  }
}

