// IngredientsPage.ets
//
// 冰箱食材: add/remove ingredients and see dish recommendations sorted by
// ingredient match %.
import { Theme, BrandGradient } from '../common/Theme';
import { SvgIcon } from '../common/SvgIcon';
import { DishCard, DishTag } from '../components/DishCard';
import { EmptyState } from '../components/EmptyState';
import { Ingredient } from '../common/models/Models';
import { AppStore } from '../common/store/AppStore';
import { RecommendService } from '../common/services/RecommendService';
import { DishRecommendation } from '../common/models/Models';
import { promptAction } from '@kit.ArkUI';

@Component
export struct IngredientsPage {
  @State inputText: string = '';
  @StorageLink('ingredients') ingredients: Ingredient[] = [];

  build() {
    Column() {
      Scroll() {
        Column() {
          this.Header()
          this.InputCard()
          this.MyIngredientsSection()
          this.RecommendSection()
        }
        .width('100%')
        .alignItems(HorizontalAlign.Start)
      }
      .layoutWeight(1)
      .scrollBar(BarState.Off)
      .align(Alignment.Start)
    }
    .width('100%')
    .height('100%')
    .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding })
  }

  @Builder
  Header(): void {
    Column() {
      Text('冰箱食材')
        .fontSize(26)
        .fontWeight(FontWeight.Bold)
        .fontColor(Theme.textPrimary)
      Text('告诉我你有什么，我帮你决定怎么吃')
        .fontSize(15)
        .fontColor(Theme.textSecondary)
        .margin({ top: 4 })
    }
    .width('100%')
    .alignItems(HorizontalAlign.Start)
    .padding({ top: Theme.headerTopPadding, bottom: 24 })
  }

  @Builder
  InputCard(): void {
    Row() {
      TextInput({ text: this.inputText, placeholder: '输入食材，例如：鸡蛋' })
        .id('ingredient-input')
        .layoutWeight(1)
        .height(52)
        .fontSize(15)
        .fontColor(Theme.textPrimary)
        .placeholderColor(Theme.textPlaceholder)
        .backgroundColor(Theme.surfaceSecondary)
        .borderRadius(Theme.radiusInput)
        .borderWidth(1)
        .borderColor(Theme.borderSoft)
        .onChange((value: string) => { this.inputText = value; })
        .onSubmit(() => this.addIngredient())

      Column() {
        SvgIcon({ variant: 'add', iconSize: 24, color: Theme.textOnPrimary })
      }
      .id('ingredient-add-button')
      .width(52)
      .height(52)
      .borderRadius(Theme.radiusInput)
      .linearGradient(BrandGradient.primary)
      .shadow({ radius: 12, color: 'rgba(232,166,60,0.35)', offsetY: 4 })
      .justifyContent(FlexAlign.Center)
      .alignItems(HorizontalAlign.Center)
      .margin({ left: 10 })
      .onClick(() => this.addIngredient())
    }
    .width('100%')
    .padding(20)
    .backgroundColor(Theme.cardBg)
    .border({ width: 1, color: Theme.borderSoft })
    .borderRadius(Theme.radiusCard)
    .shadow({ radius: 30, color: 'rgba(59,50,42,0.12)', offsetY: 10 })
    .alignItems(VerticalAlign.Center)
    .margin({ bottom: 20 })
  }

  @Builder
  MyIngredientsSection(): void {
    Column() {
      Row() {
        Text('我的食材')
          .fontSize(20)
          .fontWeight(FontWeight.Medium)
          .fontColor(Theme.textPrimary)
        Blank()
        Text(`${this.ingredients.length} 种`)
          .fontSize(12)
          .fontWeight(FontWeight.Medium)
          .fontColor(Theme.textSecondary)
          .backgroundColor(Theme.surfaceSecondary)
          .borderRadius(Theme.radiusTag)
          .padding({ left: 10, right: 10, top: 4, bottom: 4 })
      }
      .width('100%')
      .alignItems(VerticalAlign.Center)
      .margin({ bottom: 14 })

      if (this.ingredients.length === 0) {
        EmptyState({
          iconVariant: 'empty-fridge',
          title: '冰箱还是空的',
          subtitle: '添加食材，发现更多美味可能',
          targetId: 'ingredient-empty-state'
        })
      } else {
        // ingredient-list wraps the chips. The list id sits on the container.
        Flex({ wrap: FlexWrap.Wrap }) {
          ForEach(this.ingredients, (item: Ingredient) => {
            Row() {
              Text(item.name)
                .fontSize(14)
                .fontWeight(FontWeight.Medium)
                .fontColor(Theme.textPrimary)
              Row() {
                SvgIcon({ variant: 'delete', iconSize: 18, color: Theme.textSecondary })
              }
              .id(`ingredient-delete-${item.id}`)
              .width(28)
              .height(28)
              .justifyContent(FlexAlign.Center)
              .alignItems(HorizontalAlign.Center)
              .margin({ left: 8 })
              .onClick(() => AppStore.deleteIngredient(item.id))
            }
            .id(`ingredient-item-${item.id}`)
            .padding({ left: 14, right: 10, top: 10, bottom: 10 })
            .backgroundColor(Theme.cardBg)
            .border({ width: 1, color: Theme.borderSoft })
            .borderRadius(Theme.radiusChip)
            .shadow({ radius: 8, color: 'rgba(59,50,42,0.08)', offsetY: 2 })
            .alignItems(VerticalAlign.Center)
            .margin({ right: 10, bottom: 10 })
          }, (item: Ingredient) => item.id)
        }
        .id('ingredient-list')
        .width('100%')
      }
    }
    .width('100%')
    .alignItems(HorizontalAlign.Start)
    .margin({ bottom: 20 })
  }

  @Builder
  RecommendSection(): void {
    Column() {
      Text('为你推荐')
        .fontSize(20)
        .fontWeight(FontWeight.Medium)
        .fontColor(Theme.textPrimary)
        .margin({ bottom: 14 })

      this.RecommendBody()
    }
    .width('100%')
    .alignItems(HorizontalAlign.Start)
  }

  @Builder
  RecommendBody(): void {
    if (this.ingredients.length === 0) {
      EmptyState({
        iconVariant: 'no-recommend',
        title: '暂时无推荐',
        subtitle: '添加食材，美味就会出现',
        targetId: 'ingredient-recommend-empty-state'
      })
    } else {
      Column() {
        ForEach(RecommendService.recommend(this.ingredients), (rec: DishRecommendation, idx: number) => {
          Column() {
            DishCard({
              name: rec.dish.name,
              meta: this.buildRecMeta(rec),
              tags: this.buildRecTags(rec),
              iconVariant: this.dishVariant(idx),
              matchPercent: rec.matchPercent,
              targetId: `ingredient-dish-${rec.dish.id}`,
              onSelect: () => {
                promptAction.showToast({ message: `已选择 ${rec.dish.name}`, duration: 1500 });
              }
            })
          }
          .margin({ bottom: 14 })
        }, (rec: DishRecommendation) => rec.dish.id)
      }
      .id('ingredient-recommend-list')
      .width('100%')
      .alignItems(HorizontalAlign.Start)
    }
  }

  private addIngredient(): void {
    const name = this.inputText.trim();
    if (name.length === 0) {
      return;
    }
    const ok = AppStore.addIngredient(name);
    if (ok) {
      this.inputText = '';
    } else {
      promptAction.showToast({ message: '食材已存在或为空', duration: 1500 });
    }
  }

  private buildRecMeta(rec: DishRecommendation): string {
    const matched = rec.matched.length > 0 ? `已匹配 ${rec.matched.join('、')}` : '';
    const missing = rec.missing.length > 0 ? ` · 还缺 ${rec.missing.join('、')}` : '';
    return `${matched}${missing}`;
  }

  private buildRecTags(rec: DishRecommendation): DishTag[] {
    const tags: DishTag[] = [];
    rec.dish.tags.forEach((t, i) => {
      if (i >= 2) {
        return;
      }
      tags.push({ label: t, color: i === 0 ? Theme.mustard : '' });
    });
    tags.push({ label: `${rec.dish.minutes} 分钟`, color: '' });
    return tags;
  }

  private dishVariant(idx: number): string {
    const variants: string[] = ['dish1', 'dish2', 'dish3', 'dish4'];
    return variants[idx % variants.length];
  }
}

