// FilterPage.ets
//
// 筛选推荐: pick moods + meal time, then see matching dishes.
import { Theme, BrandGradient } from '../common/Theme';
import { SvgIcon } from '../common/SvgIcon';
import { DishCard, DishTag } from '../components/DishCard';
import { EmptyState } from '../components/EmptyState';
import { Dish, MoodKey, TimeKey, MOOD_LABELS, MOOD_COLORS, TIME_LABELS, MOOD_ORDER, TIME_ORDER } from '../common/models/Models';
import { FilterService } from '../common/services/FilterService';
import { promptAction } from '@kit.ArkUI';

@Component
export struct FilterPage {
  @State selectedMoods: MoodKey[] = ['crave'];
  @State selectedTime: TimeKey = 'lunch';
  @State results: Dish[] = [];

  aboutToAppear(): void {
    this.applyFilter();
  }

  build() {
    Column() {
      Scroll() {
        Column() {
          this.Header()
          this.FilterCard()
          this.ResultSection()
        }
        .width('100%')
        .alignItems(HorizontalAlign.Start)
      }
      .layoutWeight(1)
      .scrollBar(BarState.Off)
      .align(Alignment.Start)
    }
    .width('100%')
    .height('100%')
    .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding })
  }

  @Builder
  Header(): void {
    Column() {
      Text('筛选推荐')
        .fontSize(26)
        .fontWeight(FontWeight.Bold)
        .fontColor(Theme.textPrimary)
      Text('按心情和用餐时间，找到此刻最对味的菜')
        .fontSize(15)
        .fontColor(Theme.textSecondary)
        .margin({ top: 4 })
    }
    .width('100%')
    .alignItems(HorizontalAlign.Start)
    .padding({ top: Theme.headerTopPadding, bottom: 24 })
  }

  @Builder
  FilterCard(): void {
    Column() {
      this.MoodGroup()
      Column().height(20)
      this.TimeGroup()
      Column().height(6)

      Row({ space: 12 }) {
        Button('重置')
          .id('filter-reset-button')
          .type(ButtonType.Normal)
          .layoutWeight(1)
          .height(50)
          .fontSize(15)
          .fontWeight(FontWeight.Medium)
          .fontColor(Theme.textPrimary)
          .backgroundColor(Color.Transparent)
          .border({ width: 1.5, color: Theme.textPrimary })
          .borderRadius(Theme.radiusSecondaryButton)
          .onClick(() => this.resetFilter())

        Button('应用筛选')
          .id('filter-apply-button')
          .type(ButtonType.Normal)
          .layoutWeight(1)
          .height(50)
          .fontSize(16)
          .fontWeight(FontWeight.Medium)
          .fontColor(Theme.textOnPrimary)
          .linearGradient(BrandGradient.primary)
          .shadow({ radius: 18, color: 'rgba(232,166,60,0.40)', offsetY: 6 })
          .borderRadius(Theme.radiusButton)
          .onClick(() => this.applyFilter())
      }
      .width('100%')
      .margin({ top: 6 })
    }
    .width('100%')
    .padding(20)
    .backgroundColor(Theme.cardBg)
    .border({ width: 1, color: Theme.borderSoft })
    .borderRadius(Theme.radiusCard)
    .shadow({ radius: 30, color: 'rgba(59,50,42,0.12)', offsetY: 10 })
    .alignItems(HorizontalAlign.Start)
    .margin({ bottom: 20 })
  }

  @Builder
  MoodGroup(): void {
    Column() {
      Row() {
        SvgIcon({ variant: 'mood', iconSize: 18, color: Theme.mustard })
        Text('今天的心情')
          .fontSize(15)
          .fontWeight(FontWeight.Medium)
          .fontColor(Theme.textPrimary)
          .margin({ left: 8 })
      }
      .margin({ bottom: 12 })

      Flex({ wrap: FlexWrap.Wrap, space: { main: { value: 10, unit: LengthUnit.VP }, cross: { value: 10, unit: LengthUnit.VP } } }) {
        ForEach(MOOD_ORDER, (mood: MoodKey) => {
          this.MoodChip(mood)
        }, (mood: MoodKey) => mood)
      }
      .id('filter-mood-group')
      .width('100%')
    }
    .width('100%')
    .alignItems(HorizontalAlign.Start)
  }

  @Builder
  MoodChip(mood: MoodKey): void {
    Text(MOOD_LABELS[mood])
      .fontSize(14)
      .fontWeight(FontWeight.Medium)
      .fontColor(this.isMoodSelected(mood) ? Theme.textOnPrimary : Theme.textPrimary)
      .backgroundColor(this.isMoodSelected(mood) ? MOOD_COLORS[mood] : Theme.surfaceSecondary)
      .borderRadius(Theme.radiusChip)
      .padding({ left: 16, right: 16, top: 10, bottom: 10 })
      .shadow(this.isMoodSelected(mood) ? { radius: 8, color: 'rgba(232,166,60,0.35)', offsetY: 2 } : { radius: 0, color: Color.Transparent })
      .onClick(() => this.toggleMood(mood))
  }

  @Builder
  TimeGroup(): void {
    Column() {
      Row() {
        SvgIcon({ variant: 'time', iconSize: 18, color: Theme.mustard })
        Text('用餐时间')
          .fontSize(15)
          .fontWeight(FontWeight.Medium)
          .fontColor(Theme.textPrimary)
          .margin({ left: 8 })
      }
      .margin({ bottom: 12 })

      Flex({ wrap: FlexWrap.Wrap, space: { main: { value: 10, unit: LengthUnit.VP }, cross: { value: 10, unit: LengthUnit.VP } } }) {
        ForEach(TIME_ORDER, (time: TimeKey) => {
          Text(TIME_LABELS[time])
            .fontSize(14)
            .fontWeight(FontWeight.Medium)
            .fontColor(this.selectedTime === time ? Theme.textOnPrimary : Theme.textPrimary)
            .backgroundColor(this.selectedTime === time ? Theme.mustard : Theme.surfaceSecondary)
            .borderRadius(Theme.radiusChip)
            .padding({ left: 16, right: 16, top: 10, bottom: 10 })
            .onClick(() => { this.selectedTime = time; })
        }, (time: TimeKey) => time)
      }
      .id('filter-time-group')
      .width('100%')
    }
    .width('100%')
    .alignItems(HorizontalAlign.Start)
  }

  @Builder
  ResultSection(): void {
    Column() {
      Row() {
        Text('推荐结果')
          .fontSize(20)
          .fontWeight(FontWeight.Medium)
          .fontColor(Theme.textPrimary)
        Blank()
        Text(`${this.results.length} 道菜`)
          .fontSize(13)
          .fontColor(Theme.textSecondary)
      }
      .width('100%')
      .alignItems(VerticalAlign.Center)
      .margin({ bottom: 14 })

      if (this.results.length === 0) {
        EmptyState({
          iconVariant: 'no-result',
          title: '没有符合条件的菜',
          subtitle: '换个心情或时间再试试',
          targetId: 'filter-empty-state'
        })
      } else {
        Column() {
          ForEach(this.results, (dish: Dish, idx: number) => {
            Column() {
              DishCard({
                name: dish.name,
                meta: this.buildMeta(dish),
                tags: this.buildTags(dish),
                iconVariant: this.dishVariant(idx),
                matchPercent: -1,
                targetId: `filter-dish-${dish.id}`,
                onSelect: () => {
                  promptAction.showToast({ message: `已选择 ${dish.name}`, duration: 1500 });
                }
              })
            }
            .margin({ bottom: 14 })
          }, (dish: Dish) => dish.id)
        }
        .id('filter-result-list')
        .width('100%')
        .alignItems(HorizontalAlign.Start)
      }
    }
    .width('100%')
    .alignItems(HorizontalAlign.Start)
  }

  private isMoodSelected(mood: MoodKey): boolean {
    return this.selectedMoods.includes(mood);
  }

  private toggleMood(mood: MoodKey): void {
    if (this.isMoodSelected(mood)) {
      this.selectedMoods = this.selectedMoods.filter((m) => m !== mood);
    } else {
      this.selectedMoods = [...this.selectedMoods, mood];
    }
  }

  private applyFilter(): void {
    this.results = FilterService.filter(this.selectedMoods, this.selectedTime);
  }

  private resetFilter(): void {
    this.selectedMoods = [];
    this.selectedTime = 'lunch';
    this.results = FilterService.filter([], 'lunch');
    promptAction.showToast({ message: '已重置筛选', duration: 1200 });
  }

  private buildMeta(dish: Dish): string {
    const timeLabel = dish.timeSlots.length > 0 ? TIME_LABELS[dish.timeSlots[0]] : '';
    const moodLabel = dish.moods.length > 0 ? MOOD_LABELS[dish.moods[0]] : '';
    return `${timeLabel} · ${moodLabel} · ${dish.minutes} 分钟`;
  }

  private buildTags(dish: Dish): DishTag[] {
    const tags: DishTag[] = [];
    dish.moods.forEach((m) => tags.push({ label: MOOD_LABELS[m], color: MOOD_COLORS[m] }));
    dish.timeSlots.forEach((t) => tags.push({ label: TIME_LABELS[t], color: Theme.mustard }));
    return tags.slice(0, 3);
  }

  private dishVariant(idx: number): string {
    const variants: string[] = ['dish1', 'dish2', 'dish3', 'dish4'];
    return variants[idx % variants.length];
  }
}

