// HistoryPage.ets
//
// 饮食打卡: stats, reverse-chronological timeline, add-record bottom sheet,
// and a share-card bottom sheet.
import { Theme, BrandGradient } from '../common/Theme';
import { SvgIcon } from '../common/SvgIcon';
import { EmptyState } from '../components/EmptyState';
import { DishRecord } from '../common/models/Models';
