  '把今天的味道，认真记下来。',
  '人间烟火气，最抚凡人心。',
];

@Component
export struct HistoryPage {
  @StorageLink('records') records: DishRecord[] = [];
  @State addSheetVisible: boolean = false;
  @State shareSheetVisible: boolean = false;
  @State newRecordText: string = '';
  @State activeShareRecord: DishRecord | null = null;

  build() {
    Stack() {
      Column() {
        Scroll() {
          Column() {
            this.Header()
            this.StatsCard()
            this.TimelineSection()
          }
          .width('100%')
          .alignItems(HorizontalAlign.Start)
        }
        .layoutWeight(1)
        .scrollBar(BarState.Off)
        .align(Alignment.Start)
      }
      .width('100%')
      .height('100%')
      .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding })

      if (this.addSheetVisible) {
        this.AddSheet()
      }
      if (this.shareSheetVisible) {
        this.ShareSheet()
      }
    }
    .width('100%')
    .height('100%')
    .alignContent(Alignment.Bottom)
  }

  @Builder
  Header(): void {
    Row() {
      Column() {
        Text('饮食打卡')
          .fontSize(26)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.textPrimary)
        Text('记录每一餐的小确幸')
          .fontSize(15)
          .fontColor(Theme.textSecondary)
          .margin({ top: 4 })
      }
      .alignItems(HorizontalAlign.Start)
      .layoutWeight(1)

      Column() {
        SvgIcon({ variant: 'add-record', iconSize: 24, color: Theme.textOnPrimary })
      }
      .id('history-add-button')
      .width(48)
      .height(48)
      .borderRadius(24)
      .linearGradient(BrandGradient.primary)
      .shadow({ radius: 18, color: 'rgba(232,166,60,0.40)', offsetY: 6 })
      .justifyContent(FlexAlign.Center)
      .alignItems(HorizontalAlign.Center)
      .onClick(() => { this.newRecordText = ''; this.addSheetVisible = true; })
    }
    .width('100%')
    .alignItems(VerticalAlign.Bottom)
    .padding({ top: Theme.headerTopPadding, bottom: 24 })
  }

  @Builder
  StatsCard(): void {
    Row() {
      this.Stat(`${this.weekCount()}`, '本周打卡')
      this.Stat(`${this.streakDays()}`, '连续天数')
      this.Stat(`${this.records.length}`, '分享卡片')
    }
    .width('100%')
    .padding(20)
    .backgroundColor(Theme.cardBg)
    .border({ width: 1, color: Theme.borderSoft })
    .borderRadius(Theme.radiusCard)
    .shadow({ radius: 30, color: 'rgba(59,50,42,0.12)', offsetY: 10 })
    .justifyContent(FlexAlign.SpaceAround)
    .margin({ bottom: 24 })
  }

  @Builder
  Stat(value: string, label: string): void {
    Column() {
      Text(value)
        .fontSize(28)
        .fontWeight(FontWeight.Bold)
        .fontColor(Theme.mustard)
        .margin({ bottom: 6 })
      Text(label)
        .fontSize(13)
        .fontColor(Theme.textSecondary)
    }
    .alignItems(HorizontalAlign.Center)
    .layoutWeight(1)
  }

  @Builder
  TimelineSection(): void {
    Column() {
      Text('时间线')
        .fontSize(20)
        .fontWeight(FontWeight.Medium)
        .fontColor(Theme.textPrimary)
        .margin({ bottom: 14 })

      if (this.records.length === 0) {
        EmptyState({
          iconVariant: 'empty-record',
          title: '还没有记录',
          subtitle: '点击右上角 +，写下今天吃了什么',
          targetId: 'history-empty-state'
        })
      } else {
        Column() {
          ForEach(this.records, (record: DishRecord) => {
            Column() {
              Text(Format.recordTime(record.timestamp))
                .fontSize(13)
                .fontColor(Theme.textSecondary)
                .margin({ bottom: 6 })
              Text(record.text)
                .fontSize(16)
                .fontWeight(FontWeight.Medium)
                .fontColor(Theme.textPrimary)
                .lineHeight(24)
                .margin({ bottom: 12 })

              Row() {
                Row() {
                  SvgIcon({ variant: 'share-record', iconSize: 18, color: Theme.textSecondary })
                  Text('生成卡片')
                    .fontSize(13)
                    .fontWeight(FontWeight.Medium)
                    .fontColor(Theme.textSecondary)
                    .margin({ left: 6 })
                }
                .id('history-share-button')
                .onClick(() => this.openShare(record))
              }
              .alignItems(VerticalAlign.Center)
            }
            .id(`history-record-${record.id}`)
            .width('100%')
            .padding({ left: 20, right: 20, top: 18, bottom: 18 })
            .backgroundColor(Theme.cardBg)
            .border({ width: 1, color: Theme.borderSoft })
            .borderRadius(Theme.radiusCard)
            .shadow({ radius: 30, color: 'rgba(59,50,42,0.12)', offsetY: 10 })
            .alignItems(HorizontalAlign.Start)
            .margin({ bottom: 16 })
          }, (record: DishRecord) => record.id)
        }
        .id('history-list')
        .width('100%')
        .alignItems(HorizontalAlign.Start)
      }
    }
    .width('100%')
    .alignItems(HorizontalAlign.Start)
  }

  @Builder
  AddSheet(): void {
    Stack() {
      Column()
        .width('100%')
        .height('100%')
        .backgroundColor(Theme.backdrop)
        .onClick(() => { this.addSheetVisible = false; })

      Column() {
        Row() {
          Text('添加打卡')
            .fontSize(20)
            .fontWeight(FontWeight.Medium)
            .fontColor(Theme.textPrimary)
          Blank()
          Column() {
            SvgIcon({ variant: 'close', iconSize: 18, color: Theme.textSecondary })
          }
          .width(32)
          .height(32)
          .borderRadius(16)
          .backgroundColor(Theme.surfaceSecondary)
          .justifyContent(FlexAlign.Center)
          .alignItems(HorizontalAlign.Center)
          .onClick(() => { this.addSheetVisible = false; })
        }
        .width('100%')
        .alignItems(VerticalAlign.Center)
        .margin({ bottom: 20 })

