        .width('100%')
        .alignItems(VerticalAlign.Center)
        .margin({ bottom: 20 })

        // Share card preview.
        Column() {
          Text(this.shareDateLabel())
            .fontSize(13)
            .fontColor(Theme.textSecondary)
            .margin({ bottom: 12 })
          Text(this.shareTitle())
            .fontSize(24)
            .fontWeight(FontWeight.Bold)
            .fontColor(Theme.textPrimary)
            .margin({ bottom: 10 })
          Text(`“${this.shareQuote()}”`)
            .fontSize(15)
            .fontColor(Theme.textSecondary)
            .lineHeight(22)

          Row({ space: 12 }) {
