          .margin({ top: 20 })
          .justifyContent(FlexAlign.Center)
        }
        .width('100%')
        .padding(28)
        .linearGradient(BrandGradient.shareWash)
        .border({ width: 1, color: Theme.borderDashed, style: BorderStyle.Dashed })
        .borderRadius(Theme.radiusHero)
        .alignItems(HorizontalAlign.Center)
        .margin({ bottom: 20 })

        Button() {
          Row() {
            SvgIcon({ variant: 'save-card', iconSize: 18, color: Theme.textOnPrimary })
            Text('保存卡片')
              .fontSize(16)
              .fontWeight(FontWeight.Medium)
              .fontColor(Theme.textOnPrimary)
              .margin({ left: 6 })
          }
        }
        .id('history-share-save-button')
        .type(ButtonType.Normal)
        .width('100%')
        .height(52)
        .linearGradient(BrandGradient.primary)
        .shadow({ radius: 18, color: 'rgba(232,166,60,0.40)', offsetY: 6 })
        .borderRadius(Theme.radiusButton)
        .onClick(() => {
          promptAction.showToast({ message: '卡片已保存到相册', duration: 1500 });
        })
      }
      .id('history-share-sheet')
      .width('100%')
      .padding({ left: 22, right: 22, top: 28, bottom: 32 })
      .backgroundColor(Theme.cardBg)
      .borderRadius({ topLeft: Theme.radiusSheetTop, topRight: Theme.radiusSheetTop })
    }
    .width('100%')
    .height('100%')
    .alignContent(Alignment.Bottom)
  }

  private saveRecord(): void {
    const ok = AppStore.addRecord(this.newRecordText);
    if (ok) {
      this.newRecordText = '';
      this.addSheetVisible = false;
    } else {
      promptAction.showToast({ message: '写点什么再保存吧', duration: 1500 });
    }
  }

  private openShare(record: DishRecord): void {
    this.activeShareRecord = record;
    this.shareSheetVisible = true;
  }

  private shareTitle(): string {
    return this.activeShareRecord !== null ? this.activeShareRecord.text : '今天吃了什么';
  }

  private shareDateLabel(): string {
    const ts = this.activeShareRecord !== null ? this.activeShareRecord.timestamp : Date.now();
    return `${Format.shareDate(ts)} · 今天吃什么`;
  }

  private shareQuote(): string {
    const id = this.activeShareRecord !== null ? this.activeShareRecord.id : '';
    let hash = 0;
    for (let i = 0; i < id.length; i++) {
      hash = (hash + id.charCodeAt(i)) % SHARE_QUOTES.length;
    }
    return SHARE_QUOTES[hash];
  }

  private weekCount(): number {
    const now = Date.now();
    const weekAgo = now - 7 * 24 * 60 * 60 * 1000;
    return this.records.filter((r) => r.timestamp >= weekAgo).length;
  }

  private streakDays(): number {
    if (this.records.length === 0) {
      return 0;
    }
    const daySet = new Set<number>();
    this.records.forEach((r) => {
      const d = new Date(r.timestamp);
      daySet.add(new Date(d.getFullYear(), d.getMonth(), d.getDate()).getTime());
    });
    let streak = 0;
    const today = new Date();
    let cursor = new Date(today.getFullYear(), today.getMonth(), today.getDate()).getTime();
    while (daySet.has(cursor)) {
      streak += 1;
      cursor -= 24 * 60 * 60 * 1000;
    }
    return streak;
  }
}

