    return `${Format.shareDate(ts)} · 今天吃什么`;
  }

  private shareQuote(): string {
    const id = this.activeShareRecord !== null ? this.activeShareRecord.id : '';
    let hash = 0;
    for (let i = 0; i < id.length; i++) {
      hash = (hash + id.charCodeAt(i)) % SHARE_QUOTES.length;
    }
    return SHARE_QUOTES[hash];
  }

  private weekCount(): number {
    const now = Date.now();
    const weekAgo = now - 7 * 24 * 60 * 60 * 1000;
    return this.records.filter((r) => r.timestamp >= weekAgo).length;
  }

  private streakDays(): number {
    if (this.records.length === 0) {
      return 0;
    }
    const daySet = new Set<number>();
    this.records.forEach((r) => {
      const d = new Date(r.timestamp);
      daySet.add(new Date(d.getFullYear(), d.getMonth(), d.getDate()).getTime());
    });
    let streak = 0;
    const today = new Date();
    let cursor = new Date(today.getFullYear(), today.getMonth(), today.getDate()).getTime();
    while (daySet.has(cursor)) {
      streak += 1;
      cursor -= 24 * 60 * 60 * 1000;
    }
    return streak;
  }
}

