// Models.ets
//
// Domain models for 今天吃什么. Shared across services, store, and pages.

// Mood keys (match ui-behavior.json moodKeys)
export type MoodKey = 'crave' | 'light' | 'diet' | 'treat';
// Time keys (match ui-behavior.json timeKeys)
export type TimeKey = 'breakfast' | 'lunch' | 'dinner' | 'lateNight';

// Built-in catalog dish. This is a recipe catalog (allowed by spec), not
// seeded user data. Used by wheel, filter, and ingredient recommendations.
export interface Dish {
  id: string;
  name: string;
  tags: string[];        // display labels, e.g. 家常菜, 清淡, 快手
  moods: MoodKey[];      // mood contexts this dish fits
  timeSlots: TimeKey[];  // meal times this dish fits
  ingredients: string[]; // common ingredients (for ingredient matching)
  minutes: number;
}

// A user ingredient persisted in the fridge.
export interface Ingredient {
  id: string;
  name: string;
}

// A daily eating check-in record.
export interface DishRecord {
  id: string;
  text: string;
  timestamp: number; // epoch ms
}

// A dish scored against the user's current ingredients.
export interface DishRecommendation {
  dish: Dish;
  matched: string[];
  missing: string[];
  matchPercent: number;
}

interface MoodLabelMap { crave: string; light: string; diet: string; treat: string }
interface MoodColorMap { crave: string; light: string; diet: string; treat: string }
interface TimeLabelMap { breakfast: string; lunch: string; dinner: string; lateNight: string }

export const MOOD_LABELS: MoodLabelMap = {
  crave: '想吃爽',
  light: '清淡点',
  diet: '减脂中',
  treat: '想犒劳',
};

export const MOOD_COLORS: MoodColorMap = {
  crave: '#D94E41',
  light: '#4A8B5D',
  diet: '#E8A63C',
  treat: '#A88FB8',
};

export const TIME_LABELS: TimeLabelMap = {
  breakfast: '早餐',
  lunch: '午餐',
  dinner: '晚餐',
  lateNight: '夜宵',
};

export const MOOD_ORDER: MoodKey[] = ['crave', 'light', 'diet', 'treat'];
export const TIME_ORDER: TimeKey[] = ['breakfast', 'lunch', 'dinner', 'lateNight'];

