  onSelect: () => void = () => {};

  build() {
    Row() {
      Column() {
        SvgIcon({ variant: this.iconVariant, iconSize: 24, color: Theme.caramel })
      }
      .width(48)
      .height(48)
      .borderRadius(Theme.radiusIconTile)
      .backgroundColor(Theme.surfaceSecondary)
      .justifyContent(FlexAlign.Center)
      .alignItems(HorizontalAlign.Center)

      Column() {
        Text(this.name)
          .fontSize(17)
          .fontWeight(FontWeight.Medium)
          .fontColor(Theme.textPrimary)
          .margin({ bottom: 4 })

        if (this.meta.length > 0) {
          Text(this.meta)
            .fontSize(13)
            .fontColor(Theme.textSecondary)
            .margin({ bottom: 6 })
        }

        if (this.tags.length > 0) {
          Flex({ wrap: FlexWrap.Wrap }) {
            ForEach(this.tags, (tag: DishTag, idx: number) => {
              Text(tag.label)
                .fontSize(11)
                .fontWeight(FontWeight.Medium)
                .fontColor(tag.color.length > 0 ? Theme.textOnPrimary : Theme.textPrimary)
                .backgroundColor(tag.color.length > 0 ? tag.color : Theme.surfaceSecondary)
                .borderRadius(Theme.radiusTag)
                .padding({ left: 10, right: 10, top: 4, bottom: 4 })
                .margin({ right: 6, bottom: 4 })
            }, (tag: DishTag, idx: number) => `${idx}-${tag.label}`)
          }
        }
      }
      .layoutWeight(1)
      .alignItems(HorizontalAlign.Start)
      .margin({ left: 14 })

      if (this.matchPercent >= 0) {
        Text(`${this.matchPercent}%`)
          .fontSize(12)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.textOnPrimary)
          .linearGradient(BrandGradient.primary)
          .borderRadius(Theme.radiusTag)
          .padding({ left: 10, right: 10, top: 6, bottom: 6 })
      }
    }
    .id(this.targetId)
    .width('100%')
    .padding({ left: 20, right: 20, top: 18, bottom: 18 })
    .backgroundColor(Theme.cardBg)
    .border({ width: 1, color: Theme.borderSoft })
    .borderRadius(Theme.radiusCard)
    .shadow({ radius: 30, color: 'rgba(59,50,42,0.12)', offsetY: 10 })
    .alignItems(VerticalAlign.Center)
    .onClick(() => this.onSelect())
  }
}

