// Toast.ets
//
// Centralized promptAction.showToast wrapper. promptAction may throw, so all
// call sites route through here instead of duplicating try/catch.
import { promptAction } from '@kit.ArkUI';

export class Toast {
  static show(message: string, duration: number = 1500): void {
    try {
      promptAction.showToast({ message, duration });
    } catch (e) {
      // best-effort UI feedback; ignore failures silently
    }
  }
}

